import{_ as r,C as i,o,c as d,a3 as t,b as s,w as a,a as n,E as l,a4 as p}from"./chunks/framework.CRbjHCyB.js";const k=JSON.parse('{"title":"系统架构","description":"","frontmatter":{},"headers":[],"relativePath":"zh/catter/design/architecture.md","filePath":"zh/catter/design/architecture.md"}'),E={name:"zh/catter/design/architecture.md"};function h(A,e,g,C,x,m){const c=i("Mermaid");return o(),d("div",null,[e[1]||(e[1]=t('<h1 id="系统架构" tabindex="-1">系统架构 <a class="header-anchor" href="#系统架构" aria-label="Permalink to &quot;系统架构&quot;">​</a></h1><p>Catter 是一个三层协作系统，用于拦截和处理构建命令。每个组件各司其职，通过 IPC 通信组成一条管线，捕获构建系统发出的每一条编译器调用。</p><h2 id="三大组件" tabindex="-1">三大组件 <a class="header-anchor" href="#三大组件" aria-label="Permalink to &quot;三大组件&quot;">​</a></h2><h3 id="_1-hook-进程创建拦截器" tabindex="-1">1. HOOK -- 进程创建拦截器 <a class="header-anchor" href="#_1-hook-进程创建拦截器" aria-label="Permalink to &quot;1. HOOK -- 进程创建拦截器&quot;">​</a></h3><p>一个平台相关的共享库，注入到构建系统的进程中。它拦截进程创建函数的调用（Unix 上的 <code>execve</code>，Windows 上的 <code>CreateProcess</code>），并重写命令，使每个子进程都通过 <code>catter-proxy</code> 中转后再执行。</p><ul><li><strong>Linux</strong>: <code>libcatter-hook-unix.so</code>，通过 <code>LD_PRELOAD</code> 注入</li><li><strong>macOS</strong>: <code>libcatter-hook-unix.dylib</code>，通过 <code>DYLD_INSERT_LIBRARIES</code> 注入</li><li><strong>Windows</strong>: <code>catter-hook-win64.dll</code>，通过 DLL 注入（<code>VirtualAllocEx</code> + <code>LoadLibraryA</code>）</li></ul><p>HOOK 是被动的 -- 它不做任何决策，仅将进程创建重定向到代理。</p><h3 id="_2-proxy-catter-proxy-编译器包装器与钩子管理器" tabindex="-1">2. PROXY（<code>catter-proxy</code>）-- 编译器包装器与钩子管理器 <a class="header-anchor" href="#_2-proxy-catter-proxy-编译器包装器与钩子管理器" aria-label="Permalink to &quot;2. PROXY（`catter-proxy`）-- 编译器包装器与钩子管理器&quot;">​</a></h3><p>一个独立的可执行文件，有两种运行模式：</p><ul><li><strong>注入模式（Injector Mode）</strong>: 由 <code>catter</code> 启动，用于运行挂载了钩子库的构建系统。这是会话中的第一个代理实例。</li><li><strong>包装模式（Wrapper Mode）</strong>: 由钩子库在拦截到构建命令时启动。每个被拦截的命令都会生成一个新的 <code>catter-proxy</code> 进程，代替原始的编译器/工具。</li></ul><p>在两种模式下，代理都会通过 IPC 连接到 <code>catter</code> 守护进程，发送捕获到的命令信息，接收决策（执行、丢弃或修改），然后据此执行操作。</p><h3 id="_3-decision-catter-守护进程" tabindex="-1">3. DECISION（<code>catter</code>）-- 守护进程 <a class="header-anchor" href="#_3-decision-catter-守护进程" aria-label="Permalink to &quot;3. DECISION（`catter`）-- 守护进程&quot;">​</a></h3><p>用户直接调用的主进程。它负责：</p><ol><li>通过内嵌的 QuickJS 运行时加载并初始化 JavaScript 脚本</li><li>以注入模式生成 <code>catter-proxy</code> 来启动构建</li><li>在 Unix 域套接字（Windows 上为命名管道）上监听 IPC 连接</li><li>从代理实例接收被拦截的命令</li><li>调用 JavaScript 回调函数（<code>onCommand</code>、<code>onExecution</code>、<code>onStart</code>、<code>onFinish</code>）来决定如何处理每条命令</li><li>维护一棵与构建进程树对应的会话树</li></ol><p>JS 运行时是单线程的 -- 所有脚本回调在事件循环上顺序执行，因此用户脚本无需处理并发问题。</p><h2 id="完整工作流程" tabindex="-1">完整工作流程 <a class="header-anchor" href="#完整工作流程" aria-label="Permalink to &quot;完整工作流程&quot;">​</a></h2><p>以下是执行如下命令时的完整步骤说明：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::cdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile_commands.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span></span></code></pre></div><ol><li><p><strong>用户调用 <code>catter</code></strong>。DECISION 守护进程启动，加载 <code>script::cdb</code> 脚本，初始化 QuickJS 运行时，执行脚本的 <code>onStart()</code> 回调。</p></li><li><p><strong><code>catter</code> 生成 <code>catter-proxy -- make</code></strong>。这是<strong>注入模式</strong>下的代理，作为 <code>catter</code> 的子进程运行。</p></li><li><p><strong>代理通过 IPC 连接到 <code>catter</code></strong>。它发送 <code>CHECK_MODE</code> 请求，确认守护进程处于注入模式。</p></li><li><p><strong><code>catter</code> 回应：注入模式</strong>。代理确认后，准备启动构建命令并挂载钩子库。</p></li><li><p><strong>代理启动带有钩子的 <code>make</code></strong>。在 Linux 上，这意味着将 <code>libcatter-hook-unix.so</code> 添加到 <code>LD_PRELOAD</code> 并设置环境变量（<code>__key_catter_proxy_path_v1</code>、<code>__key_catter_command_id_v1</code>），然后调用真正的 <code>execve</code>。在 Windows 上，进程以挂起状态创建，注入钩子 DLL 后再恢复运行。</p></li><li><p><strong><code>make</code> 运行并尝试生成 <code>g++ main.cpp -o main.o</code></strong>。构建系统调用 <code>execve(&quot;g++&quot;, ...)</code>（Windows 上为 <code>CreateProcess</code>）。</p></li><li><p><strong>HOOK 拦截 <code>execve()</code> 调用</strong>。加载在 <code>make</code> 地址空间中的钩子库在系统调用到达内核之前捕获它。</p></li><li><p><strong>HOOK 重写命令</strong>。不直接执行 <code>g++</code>，而是重写为：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>catter-proxy -p &lt;parent_id&gt; --exec /usr/bin/g++ -- g++ main.cpp -o main.o</span></span></code></pre></div><p>同时清理环境：移除 catter 专用环境变量，并从 <code>LD_PRELOAD</code> 中剥离钩子库路径，防止代理本身被钩子拦截。</p></li><li><p><strong>新的 <code>catter-proxy</code> 实例启动</strong>（<strong>包装模式</strong>下的 PROXY）。此代理实例通过真正的 <code>execve</code> 使用重写后的命令启动。</p></li><li><p><strong>包装模式代理通过 IPC 连接到 <code>catter</code></strong>。它先发送 <code>CREATE</code> 请求（以父进程 ID 注册自身），再发送 <code>MAKE_DECISION</code> 请求，包含完整的命令信息：工作目录、已解析的可执行文件路径、参数列表和环境变量。</p></li><li><p><strong><code>catter</code> 调用 JS 脚本中的 <code>onCommand(ctx)</code></strong>。脚本检查命令内容并返回一个动作：原样执行、修改后执行或丢弃。</p></li><li><p><strong>代理根据决策执行操作</strong>：</p><ul><li><strong>INJECT</strong>: 挂载钩子库后执行命令（使孙子进程也被拦截）</li><li><strong>WRAP</strong>: 直接执行命令，捕获标准输出和标准错误</li><li><strong>DROP</strong>: 跳过执行，返回退出码 0</li></ul></li><li><p><strong>执行完成后，代理向 <code>catter</code> 发送 <code>FINISH</code></strong>。结果包括退出码、标准输出和标准错误的内容。</p></li><li><p><strong><code>catter</code> 调用 JS 脚本中的 <code>onExecution(ctx)</code></strong>，传入执行结果。</p></li><li><p><strong>当 <code>make</code> 执行完毕</strong>，最初的注入模式代理退出，<code>catter</code> 调用 <code>onFinish(result)</code>。</p></li><li><p><strong><code>catter</code> 关闭</strong>，写入输出文件（例如 <code>compile_commands.json</code>）。</p></li></ol><h2 id="时序图" tabindex="-1">时序图 <a class="header-anchor" href="#时序图" aria-label="Permalink to &quot;时序图&quot;">​</a></h2>',20)),(o(),s(p,null,{default:a(()=>[l(c,{id:"mermaid-210",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20User%20as%20%E7%94%A8%E6%88%B7%0A%20%20%20%20participant%20Catter%20as%20catter%20(DECISION)%0A%20%20%20%20participant%20Proxy1%20as%20catter-proxy%20(%E6%B3%A8%E5%85%A5%E6%A8%A1%E5%BC%8F)%0A%20%20%20%20participant%20Make%20as%20make%20(%E6%9E%84%E5%BB%BA%E7%B3%BB%E7%BB%9F)%0A%20%20%20%20participant%20Hook%20as%20HOOK%20(%E5%9C%A8%20make%20%E4%B8%AD)%0A%20%20%20%20participant%20Proxy2%20as%20catter-proxy%20(%E5%8C%85%E8%A3%85%E6%A8%A1%E5%BC%8F)%0A%20%20%20%20participant%20GCC%20as%20g%2B%2B%20(%E7%BC%96%E8%AF%91%E5%99%A8)%0A%0A%20%20%20%20User-%3E%3ECatter%3A%20catter%20script%3A%3Acdb%20--%20make%0A%20%20%20%20Catter-%3E%3ECatter%3A%20%E5%8A%A0%E8%BD%BD%E8%84%9A%E6%9C%AC%EF%BC%8C%E8%B0%83%E7%94%A8%20onStart()%0A%20%20%20%20Catter-%3E%3EProxy1%3A%20%E7%94%9F%E6%88%90%20catter-proxy%20--%20make%0A%20%20%20%20Proxy1-%3E%3ECatter%3A%20IPC%3A%20CHECK_MODE%0A%20%20%20%20Catter--%3E%3EProxy1%3A%20INJECT%20%E6%A8%A1%E5%BC%8F%0A%20%20%20%20Proxy1-%3E%3EMake%3A%20%E6%8C%82%E8%BD%BD%20HOOK%20%E5%90%AF%E5%8A%A8%20make%0A%20%20%20%20Make-%3E%3EHook%3A%20execve(%22g%2B%2B%22%2C%20...)%0A%20%20%20%20Hook-%3E%3EProxy2%3A%20%E9%87%8D%E5%86%99%E4%B8%BA%20catter-proxy%20-p%20ID%20--exec%20g%2B%2B%20--%20...%0A%20%20%20%20Proxy2-%3E%3ECatter%3A%20IPC%3A%20CREATE(parent_id)%0A%20%20%20%20Catter--%3E%3EProxy2%3A%20%E6%96%B0%E4%BC%9A%E8%AF%9D%20ID%0A%20%20%20%20Proxy2-%3E%3ECatter%3A%20IPC%3A%20MAKE_DECISION(command)%0A%20%20%20%20Catter-%3E%3ECatter%3A%20%E8%B0%83%E7%94%A8%20onCommand(ctx)%0A%20%20%20%20Catter--%3E%3EProxy2%3A%20%E5%8A%A8%E4%BD%9C%3A%20%E6%89%A7%E8%A1%8C%0A%20%20%20%20Proxy2-%3E%3EGCC%3A%20%E6%89%A7%E8%A1%8C%20g%2B%2B%20main.cpp%0A%20%20%20%20GCC--%3E%3EProxy2%3A%20%E9%80%80%E5%87%BA%E7%A0%81%200%0A%20%20%20%20Proxy2-%3E%3ECatter%3A%20IPC%3A%20FINISH(result)%0A%20%20%20%20Catter-%3E%3ECatter%3A%20%E8%B0%83%E7%94%A8%20onExecution(ctx)%0A%20%20%20%20Make--%3E%3EProxy1%3A%20make%20%E9%80%80%E5%87%BA%0A%20%20%20%20Proxy1--%3E%3ECatter%3A%20%E8%BF%9B%E7%A8%8B%E7%BB%93%E6%9E%9C%0A%20%20%20%20Catter-%3E%3ECatter%3A%20%E8%B0%83%E7%94%A8%20onFinish(result)%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<h2 id="catter-proxy-的两种模式" tabindex="-1">catter-proxy 的两种模式 <a class="header-anchor" href="#catter-proxy-的两种模式" aria-label="Permalink to &quot;catter-proxy 的两种模式&quot;">​</a></h2><p>代理二进制文件根据启动方式承担不同职责：</p><h3 id="注入模式-injector-mode" tabindex="-1">注入模式（Injector Mode） <a class="header-anchor" href="#注入模式-injector-mode" aria-label="Permalink to &quot;注入模式（Injector Mode）&quot;">​</a></h3><p>由 <code>catter</code> 启动，用于运行挂载了钩子的构建系统。始终是会话中的第一个代理实例。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>catter-proxy -- make -j8</span></span></code></pre></div><p>注入模式下的代理：</p><ol><li>连接守护进程，确认注入模式</li><li>准备环境，设置 <code>LD_PRELOAD</code>（或在 Windows 上进行 DLL 注入）</li><li>设置 catter 专用环境变量供钩子读取</li><li>启动构建命令</li><li>等待构建完成，捕获标准输出和标准错误</li></ol><h3 id="包装模式-wrapper-mode" tabindex="-1">包装模式（Wrapper Mode） <a class="header-anchor" href="#包装模式-wrapper-mode" aria-label="Permalink to &quot;包装模式（Wrapper Mode）&quot;">​</a></h3><p>由钩子库在拦截到子进程创建时启动。每个被拦截的命令都会创建一个新的包装实例。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>catter-proxy -p &lt;parent_id&gt; --exec /usr/bin/g++ -- g++ main.cpp -o main.o</span></span></code></pre></div><p>包装模式下的代理：</p><ol><li>连接守护进程</li><li>通过 <code>CREATE</code> 注册为 <code>parent_id</code> 的子会话</li><li>通过 <code>MAKE_DECISION</code> 发送捕获的命令</li><li>根据守护进程的响应执行（或丢弃）命令</li><li>通过 <code>FINISH</code> 报告执行结果</li></ol><h2 id="关键设计决策" tabindex="-1">关键设计决策 <a class="header-anchor" href="#关键设计决策" aria-label="Permalink to &quot;关键设计决策&quot;">​</a></h2><p><strong>单线程 JS 运行时</strong>。所有 JavaScript 回调在事件循环上顺序执行。守护进程通过异步 I/O（使用 <code>kota</code>）并发处理 IPC 连接，但脚本执行是串行的。这消除了用户脚本中的竞态条件。</p><p><strong>基于 Unix 域套接字/命名管道的二进制 IPC</strong>。代理与守护进程之间的通信使用 <code>kota::ipc::BincodePeer</code> 进行 Bincode 序列化。这种方式快速高效，避免了文本协议的开销。详见 <a href="./ipc-protocol">IPC 协议</a>文档。</p><p><strong>递归钩子</strong>。在 Unix 上，<code>LD_PRELOAD</code> 通过环境变量被子进程继承，因此构建系统生成的任何子进程（包括嵌套的 <code>make</code> 调用、shell 脚本或构建工具包装器）都会被自动钩住。在 Windows 上，钩子 DLL 的 <code>CreateProcess</code> 替代函数确保每个子进程在开始运行前都被注入 DLL。拦截是透明且递归的 -- 构建系统无法察觉自己正在被监控。</p><p><strong>环境清理</strong>。钩子在启动代理之前会清除自身在环境中的痕迹。如果不从 <code>LD_PRELOAD</code> 中剥离钩子库，代理二进制文件本身就会被钩住，导致无限递归。代理仅在以 INJECT 动作启动需要拦截的命令时，才重新添加 <code>LD_PRELOAD</code>。</p><p><strong>会话树</strong>。守护进程维护一棵会话 ID 树，与构建进程树一一对应。每个代理实例都携带父进程的会话 ID 进行注册，使守护进程能够追踪哪些进程创建了哪些子进程。这对目标树重建和构建性能分析等功能至关重要。</p>',18))])}const _=r(E,[["render",h]]);export{k as __pageData,_ as default};
